from qiskit import QuantumCircuit
from qiskit.visualization import circuit_drawer
import matplotlib

def build():
    qc = QuantumCircuit(2)
    qc.h(0)
    qc.cx(0, 1)
    return qc

def is_fig(x):
    return isinstance(x, matplotlib.figure.Figure)

calls = {
    "A": lambda: build().draw("mpl"),
    "B": lambda: circuit_drawer(build(), output="mpl"),
    "C": lambda: build().draw("matplotlib"),
    "D": lambda: build().draw(),
    "E": lambda: circuit_drawer(build(), output="figure"),
}
evidence = {}
proven = []
for k, fn in calls.items():
    try:
        r = fn()
        ok = is_fig(r)
        evidence[k] = f"returned {type(r).__name__}; is matplotlib Figure={ok}"
        if ok:
            proven.append(k)
    except Exception as e:
        evidence[k] = f"raised {type(e).__name__}: {str(e)[:90]}"

emit_verdict({
    "answer": proven,
    "evidence": evidence,
    "observed": {"figure_returning_calls": proven},
})
